def _make_shim(tmp_path: Path, body: str) -> Path:
    root = tmp_path / "shim"
    pkg = root / "mcp_core" / "client"
    pkg.mkdir(parents=True)
    (root / "mcp_core" / "__init__.py").write_text("", encoding="utf-8")
    (pkg / "__init__.py").write_text(textwrap.dedent(body).lstrip(), encoding="utf-8")
    return root


def _shim_with_entities(tmp_path: Path, entities: list[dict[str, Any]]) -> Path:
    payload = json.dumps({"entities": entities})
    return _make_shim(
        tmp_path,
        f"""
        import json
        ENTITIES_JSON = {payload!r}

        def probe(server, **kwargs):
            return True

        def call_tool(server, tool, args=None, **kwargs):
            return json.loads(ENTITIES_JSON)

        class McpUnreachable(Exception): pass
        class McpToolError(Exception): pass
        class McpTimeout(Exception): pass
        """,
    )


