    return [
        # Fresh — 10 days old
        {
            "name": "recent-decision",
            "entityType": "decision",
            "observations": ["2026-05-10T08:00:00Z resolved", "composite=8.5"],
        },
        # Stale — 60 days old
        {
            "name": "old-decision",
            "entityType": "decision",
            "observations": ["2026-03-21T08:00:00Z resolved"],
        },
        # Stale — 200 days old
        {
            "name": "ancient-decision",
            "entityType": "assessment",
            "observations": ["2025-11-01T08:00:00Z initial"],
        },
        # No timestamp — treated as stale
        {
            "name": "undated-entity",
            "entityType": "preference",
            "observations": ["likes vim", "uses tabs"],
        },
        # Boundary case: exactly 30 days old — IS stale (>= threshold).
        {
            "name": "boundary",
            "entityType": "decision",
            "observations": ["2026-04-20T00:00:00Z exactly-30-days"],
        },
    ]


