def _run(
    reports_dir: Path,
    *,
    pythonpath: Path | None = None,
    extra_args: list[str] | None = None,
    fake_now: str | None = None,
) -> subprocess.CompletedProcess[str]:
    env = os.environ.copy()
    if pythonpath is not None:
        prev = env.get("PYTHONPATH", "")
        env["PYTHONPATH"] = f"{pythonpath}{os.pathsep}{prev}" if prev else str(pythonpath)
    argv = ["python3", str(SCRIPT_PATH), str(reports_dir)]
    if extra_args:
        argv.extend(extra_args)
    return subprocess.run(
        argv,
        env=env,
        capture_output=True,
        text=True,
        check=False,
    )


def _latest_report(reports_dir: Path, ext: str) -> Path:
    matches = sorted(reports_dir.glob(f"memory-staleness-*.{ext}"))
    assert matches, f"no .{ext} report in {reports_dir}"
    return matches[-1]


def _load_handoff(reports_dir: Path) -> dict[str, Any]:
    return json.loads(_latest_report(reports_dir, "json").read_text(encoding="utf-8"))


